def longest_word(s):
    return max(s.split(), key=len)
print(longest_word('I love programming'))

def sort_array(arr):
    for i in range(len(arr)):
        for j in range(len(arr)-1):
            if arr[j] > arr[j+1]:
                arr[j], arr[j+1] = arr[j+1], arr[j]
    return arr
print(sort_array([3, 1, 4, 2]))

def count_items(arr):
    counts = {}
    for item in arr:
        counts[item] = counts.get(item, 0) + 1
    return counts
print(count_items(['a', 'b', 'a']))

def merge_lists(l1, l2):
    return sorted(l1 + l2)
print(merge_lists([1, 3], [2, 4]))

def flatten(arr):
    return [item for sublist in arr for item in sublist]
print(flatten([[1, 2], [3, 4]]))

def is_power_of_two(n):
    return n > 0 and (n & (n - 1)) == 0
print(is_power_of_two(16))

def first_uniq_char(s):
    counts = {}
    for c in s: counts[c] = counts.get(c, 0) + 1
    for c in s:
        if counts[c] == 1: return c
    return None
print(first_uniq_char('leetcode'))

def is_valid(s):
    stack = []
    pairs = {')': '(', ']': '[', '}': '{'}
    for c in s:
        if c in pairs.values(): stack.append(c)
        elif c in pairs.keys():
            if not stack or stack.pop() != pairs[c]: return False
    return not stack
print(is_valid('()[]{}'))

def intersection(nums1, nums2):
    return list(set(nums1) & set(nums2))
print(intersection([1, 2, 2, 1], [2, 2]))

def reverse_words(s):
    return ' '.join(s.split()[::-1])
print(reverse_words('hello world'))

def contains_duplicate(nums):
    return len(nums) != len(set(nums))
print(contains_duplicate([1,2,3,1]))

def majority(nums):
    return sorted(nums)[len(nums)//2]
print(majority([2,2,1,1,1,2,2]))

def climb_stairs(n):
    a, b = 1, 1
    for _ in range(n):
        a, b = b, a + b
    return a
print(climb_stairs(3))
